import{_ as t,o as r,c as a,ae as o}from"./chunks/framework.N7L1bt_W.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md"}'),d={name:"guide/architecture.md"};function s(n,e,i,l,c,p){return r(),a("div",null,[...e[0]||(e[0]=[o(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>OWL-SDA follows a <strong>multi-agent supervisor-worker</strong> pattern. A central <code>SupervisorWorkflow</code> drives the entire generation pipeline and coordinates three types of agents:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                     SupervisorWorkflow                      │</span></span>
<span class="line"><span>│                                                             │</span></span>
<span class="line"><span>│  ┌───────────────┐   delegates   ┌────────────────────────┐ │</span></span>
<span class="line"><span>│  │   Supervisor  │ ─────────────▶│   Worker Pool (N)      │ │</span></span>
<span class="line"><span>│  │   (session)   │               │   POOL-0 … POOL-(N-1)  │ │</span></span>
<span class="line"><span>│  └───────────────┘               └────────────────────────┘ │</span></span>
<span class="line"><span>│         │                                   │               │</span></span>
<span class="line"><span>│         │ review                            │ writes        │</span></span>
<span class="line"><span>│         ▼                                   ▼               │</span></span>
<span class="line"><span>│  ┌───────────────┐          ┌───────────────────────────┐   │</span></span>
<span class="line"><span>│  │   Reviewer    │          │   WorkerTripleStore        │   │</span></span>
<span class="line"><span>│  │   (session)   │          │   (shared, in-memory)      │   │</span></span>
<span class="line"><span>│  └───────────────┘          └───────────────────────────┘   │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="generation-pipeline" tabindex="-1">Generation Pipeline <a class="header-anchor" href="#generation-pipeline" aria-label="Permalink to &quot;Generation Pipeline&quot;">​</a></h2><h3 id="_1-initialisation-owlsda" tabindex="-1">1. Initialisation (<code>OWLSDA</code>) <a class="header-anchor" href="#_1-initialisation-owlsda" aria-label="Permalink to &quot;1. Initialisation (\`OWLSDA\`)&quot;">​</a></h3><ul><li>The input OWL ontology is loaded from disk.</li><li>External ontologies referenced via <code>owl:imports</code> are fetched/cached by <code>OntologyExtractor</code>.</li><li>An optional reasoner (<code>OntologyReasoner</code>) is applied, producing an inferred model.</li><li>SHACL shapes are generated from <code>owl:Class</code> definitions for both the base and inferred model.</li><li>Sessions (workers, supervisor, reviewer) are created via the <code>SessionManager</code>.</li><li>A <code>WorkerTripleStore</code> (shared among all workers) is initialised.</li></ul><h3 id="_2-generation-rounds-supervisorworkflow" tabindex="-1">2. Generation Rounds (<code>SupervisorWorkflow</code>) <a class="header-anchor" href="#_2-generation-rounds-supervisorworkflow" aria-label="Permalink to &quot;2. Generation Rounds (\`SupervisorWorkflow\`)&quot;">​</a></h3><p>The workflow repeatedly calls <code>Supervisor.orchestrate()</code> until all shapes are processed and validation is clean:</p><ol><li><strong>Delegation</strong> — The supervisor is prompted with the list of unprocessed SHACL shapes and the current validation report. It calls <code>delegate_tasks</code> for each worker, assigning a subset of shapes.</li><li><strong>Worker execution</strong> — All delegated workers run concurrently. Each worker adds triples to the shared triple store via <code>triplestore_add</code>.</li><li><strong>Completion evaluation</strong> — After the batch completes, <code>ShapeCompletionEvaluator</code> checks which shapes now have instances in the store and no remaining SHACL violations; those shapes are marked as processed.</li><li><strong>Scope expansion</strong> — Once shapes are completing cleanly the scope is expanded (more shapes per round) using the configured <code>batch-size × pool-count</code>.</li></ol><h3 id="_3-finalisation" tabindex="-1">3. Finalisation <a class="header-anchor" href="#_3-finalisation" aria-label="Permalink to &quot;3. Finalisation&quot;">​</a></h3><p>When all shapes are processed and the store is clean:</p><ul><li>If <code>pool-count &gt; 1</code>, the supervisor performs a final editing pass over the assembled output to enforce consistency and documentation quality.</li></ul><h3 id="_4-review" tabindex="-1">4. Review <a class="header-anchor" href="#_4-review" aria-label="Permalink to &quot;4. Review&quot;">​</a></h3><p>A reviewer session reads the full output and calls <code>output_feedback</code> with one of:</p><table tabindex="0"><thead><tr><th>State</th><th>Meaning</th></tr></thead><tbody><tr><td><code>ACCEPTED</code></td><td>Output is ready; pipeline ends successfully.</td></tr><tr><td><code>REJECTED</code></td><td>Generation failed; pipeline ends with an error.</td></tr><tr><td><code>REVISION_REQUESTED</code></td><td>Specific feedback is passed back to the supervisor for targeted fixes.</td></tr></tbody></table><p>Up to <code>MAX_REVIEW_ITERATIONS</code> (3) revision cycles are attempted before the pipeline terminates.</p><h2 id="key-classes" tabindex="-1">Key Classes <a class="header-anchor" href="#key-classes" aria-label="Permalink to &quot;Key Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Class</th><th>Package</th><th>Role</th></tr></thead><tbody><tr><td><code>OWLSDA</code></td><td>root</td><td>Top-level orchestrator; wires all components together.</td></tr><tr><td><code>SupervisorWorkflow</code></td><td>generation</td><td>Drives the overall pipeline loop.</td></tr><tr><td><code>Supervisor</code></td><td>generation</td><td>Delegates shapes to workers, marks completion, finalises output.</td></tr><tr><td><code>SupervisorReviewCoordinator</code></td><td>generation</td><td>Runs the review loop between the reviewer and supervisor.</td></tr><tr><td><code>ConcurrentWorkerBatch</code></td><td>generation</td><td>Runs all worker threads for a single delegation round.</td></tr><tr><td><code>WorkerAgent</code></td><td>generation</td><td>Runnable that drives a single worker session for one round.</td></tr><tr><td><code>SessionManager</code></td><td>agent</td><td>Creates and manages all LLM sessions and their tool handlers.</td></tr><tr><td><code>SessionPool</code></td><td>agent</td><td>Thread-safe pool of worker sessions.</td></tr><tr><td><code>WorkerTripleStore</code></td><td>agent/handler</td><td>Shared in-memory RDF store written to by all workers.</td></tr><tr><td><code>OntologyExtractor</code></td><td>ontology</td><td>Fetches and caches external ontologies via HTTP.</td></tr><tr><td><code>OntologyReasoner</code></td><td>ontology</td><td>Applies Jena reasoning to derive implicit inferences.</td></tr><tr><td><code>Shacl</code></td><td>ontology</td><td>Generates, loads, saves, and validates SHACL shapes.</td></tr><tr><td><code>BenchmarkService</code></td><td>benchmark</td><td>Captures and persists per-round benchmark snapshots.</td></tr></tbody></table><h2 id="tool-handlers" tabindex="-1">Tool Handlers <a class="header-anchor" href="#tool-handlers" aria-label="Permalink to &quot;Tool Handlers&quot;">​</a></h2><p>Each agent session is equipped with a set of tool handlers (implementations of <code>SessionHandler</code>) that the LLM can invoke:</p><table tabindex="0"><thead><tr><th>Handler</th><th>Available to</th><th>Purpose</th></tr></thead><tbody><tr><td><code>ContextReaderHandler</code></td><td>all</td><td>Read named context entries.</td></tr><tr><td><code>DelegationHandler</code></td><td>supervisor</td><td>Publish instructions to a specific worker via <code>delegate_tasks</code>.</td></tr><tr><td><code>TripleStoreAddHandler</code></td><td>workers</td><td>Add Turtle triples to the shared store.</td></tr><tr><td><code>TripleStoreRemoveHandler</code></td><td>workers</td><td>Remove triples from the shared store.</td></tr><tr><td><code>TripleStoreReadHandler</code></td><td>workers</td><td>Query triples from the shared store.</td></tr><tr><td><code>TripleStoreClearHandler</code></td><td>workers</td><td>Clear all triples from the shared store.</td></tr><tr><td><code>OutputWriterHandler</code></td><td>supervisor</td><td>Write/overwrite the output file.</td></tr><tr><td><code>OutputAppendHandler</code></td><td>supervisor</td><td>Append to the output file.</td></tr><tr><td><code>OutputReplaceHandler</code></td><td>supervisor</td><td>Replace specific line ranges in the output file.</td></tr><tr><td><code>OutputReaderHandler</code></td><td>all</td><td>Read the current output file contents.</td></tr><tr><td><code>OutputValidatorHandler</code></td><td>all</td><td>Validate Turtle data against the SHACL shapes.</td></tr><tr><td><code>OutputFeedbackHandler</code></td><td>reviewer</td><td>Signal ACCEPTED / REJECTED / REVISION_REQUESTED.</td></tr><tr><td><code>ShapeStatusCheckerHandler</code></td><td>supervisor</td><td>Query which shapes are pending / completed.</td></tr><tr><td><code>WorkerProgressHandler</code></td><td>workers</td><td>Write a structured progress report context entry.</td></tr></tbody></table>`,22)])])}const g=t(d,[["render",s]]);export{u as __pageData,g as default};
